SELECT
, cg.code_group_id AS codeGroupId , cg.code_group_name AS codeGroupName , p.code_name AS parentCodeName FROM code_detail cd INNER JOIN code_group cg ON cd.code_group_seq = cg.code_group_seq LEFT JOIN code_detail p ON cd.parent_detail_seq = p.code_detail_seq WHERE 1 = 1
AND cd.code_group_seq = #{codeGroupSeq}
AND cd.parent_detail_seq = #{parentDetailSeq}
AND cd.parent_detail_seq IS NULL
AND cd.code_level = #{codeLevel}
AND cd.code_id LIKE CONCAT('%', #{codeId}, '%')
AND cd.code_value LIKE CONCAT('%', #{codeValue}, '%')
AND cd.code_name LIKE CONCAT('%', #{codeName}, '%')
AND cd.use_yn = #{useYn}
AND cd.status = #{status}
ORDER BY
cd.code_id cd.code_value cd.code_name cd.sort_order cd.create_dt cd.code_detail_seq
DESC ASC
LIMIT #{safeSize} OFFSET #{offset}

SELECT COUNT(*)
FROM code_detail cd
WHERE 1 = 1

    AND cd.code_group_seq = #{codeGroupSeq}


    AND cd.parent_detail_seq = #{parentDetailSeq}


    AND cd.parent_detail_seq IS NULL


    AND cd.code_level = #{codeLevel}


    AND cd.code_id LIKE CONCAT('%', #{codeId}, '%')


    AND cd.code_value LIKE CONCAT('%', #{codeValue}, '%')


    AND cd.code_name LIKE CONCAT('%', #{codeName}, '%')


    AND cd.use_yn = #{useYn}


    AND cd.status = #{status}

SELECT

FROM code_detail cd
WHERE cd.code_group_seq = #{codeGroupSeq}
AND cd.code_id = #{codeId}

    AND cd.code_detail_seq != #{codeDetailSeq}

LIMIT 1

