UPDATE code_detail
SET
    code_group_seq    = #{codeGroupSeq}
  , parent_detail_seq = #{parentDetailSeq}
  , code_value        = #{codeValue}
  , code_name         = #{codeName}
  , code_level        = #{codeLevel}
  , description       = #{description}
  , sort_order        = #{sortOrder}
  , use_yn            = #{useYn}
  , attr1             = #{attr1}
  , attr2             = #{attr2}
  , attr3             = #{attr3}
  , modify_dt         = NOW()
  , modify_id         = #{modifyId}
  , modify_ip         = #{modifyIp}
  , status            = #{status}
WHERE code_detail_seq = #{codeDetailSeq}
